import React, { useState } from "react";
import { Link } from "react-router-dom";
import "./Home.css";

// Example Airbnb-like listings
const heroImage = "https://images.pexels.com/photos/1643383/pexels-photo-1643383.jpeg";
const listings = [
  {
    id: 1,
    name: "Luxury Beach Villa",
    image: "https://images.pexels.com/photos/2102587/pexels-photo-2102587.jpeg",
    description: "Experience ocean views and sunsets in this luxury stay.",
  },
  {
    id: 2,
    name: "Cozy Mountain Cabin",
    image: "https://images.pexels.com/photos/277572/pexels-photo-277572.jpeg",
    description: "Peaceful retreat surrounded by snow and pine trees.",
  },
  {
    id: 3,
    name: "Modern City Apartment",
    image: "https://images.pexels.com/photos/271624/pexels-photo-271624.jpeg",
    description: "Stay close to the city center with all modern amenities.",
  },
  {
    id: 4,
    name: "Traditional Heritage Home",
    image: "https://images.pexels.com/photos/259588/pexels-photo-259588.jpeg",
    description: "Enjoy a royal experience with cultural interiors.",
  },
];

export default function Home() {
  const [searchTerm, setSearchTerm] = useState("");

  // Filter homes dynamically when typing
  const filteredListings = listings.filter((home) =>
    home.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="home-container">
      {/* Hero Section */}
      <section
        className="hero-section"
        style={{ backgroundImage: `url(${heroImage})` }}
      >
        <div className="hero-overlay">
          <h1 className="hero-title">Find Your Perfect Stay</h1>
          <p className="hero-subtitle">
            Discover homes, villas, and experiences you’ll love — just like Airbnb.
          </p>

          {/* ✅ Search bar connected to listings below */}
          <div className="search-bar">
            <input
              type="text"
              placeholder="Search stays (e.g., Villa, Cabin, Apartment...)"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            <button>Search</button>
          </div>
        </div>
      </section>

      {/* Listings Section */}
      <section className="listing-section">
        <h2 className="section-title">Featured Stays</h2>

        <div className="listing-grid">
          {filteredListings.length > 0 ? (
            filteredListings.map((home) => (
              <div key={home.id} className="listing-card">
                <img src={home.image} alt={home.name} />
                <h3>{home.name}</h3>
                <p>{home.description}</p>
                <Link to={`/booking/${home.id}`}>
                  <button className="explore-btn">Book This Stay</button>
                </Link>
              </div>
            ))
          ) : (
            <p className="no-results">No stays found 😔</p>
          )}
        </div>
      </section>
    </div>
  );
}
